1	/*
2	 * dot11_tx - TODO
3	 *
4	 * Michael Tetemke Mehari mehari.michael@gmail.com
5	 * Xianjun Jiao xianjun.jiao@ugent.be
6	 */
7	
8	`include "openofdm_tx_pre_def.v"
9	
10	module dot11_tx
11	(
12	  input  wire        clk,
13	  input  wire        phy_tx_arest,
14	
15	  input  wire        phy_tx_start,
16	  output reg         phy_tx_done,
17	  output reg         phy_tx_started,
18	
19	  input  wire [6:0]  init_pilot_scram_state,
20	  input  wire [6:0]  init_data_scram_state,
21	
22	  input  wire [63:0] bram_din,
23	  output reg  [9:0]  bram_addr,
24	
25	  input  wire        result_iq_ready,
26	  output wire        result_iq_valid,
27	  output wire [15:0] result_i,
28	  output wire [15:0] result_q
29	);
30	
31	reg  FSM3_reset;        // Reset after transmiting a whole packet
32	wire reset_int = phy_tx_arest | FSM3_reset;
33	
34	// Data collection states
35	reg [1:0] state1;
36	localparam S1_WAIT_PKT = 0;
37	localparam S1_L_SIG    = 1;
38	localparam S1_HT_SIG   = 2;
39	localparam S1_DATA     = 3;
40	reg [2:0] state11;
41	localparam S11_SERVICE   = 0;
42	localparam S11_PSDU_DATA = 1;
43	localparam S11_PSDU_CRC  = 2;
44	localparam S11_TAIL      = 3;
45	localparam S11_PAD       = 4;
46	localparam S11_RESET     = 5;
47	
48	// IQ sample generation states
49	reg [1:0] state2;
50	localparam S2_PUNC_INTERLV   = 0;
51	localparam S2_PILOT_DC_SB    = 1;
52	localparam S2_MOD_IFFT_INPUT = 2;
53	localparam S2_RESET          = 3;
54	
55	// IQ sample forwarding states
56	reg [2:0] state3;
57	localparam S3_WAIT_PKT = 0;
58	localparam S3_L_STF    = 1;
59	localparam S3_L_LTF    = 2;
60	localparam S3_L_SIG    = 3;
61	localparam S3_HT_SIG   = 4;
62	localparam S3_HT_STF   = 5;
63	localparam S3_HT_LTF   = 6;
64	localparam S3_DATA     = 7;
65	
66	reg PKT_TYPE;
67	localparam LEGACY = 0;
68	localparam HT     = 1;
69	
70	localparam NO_OUTPUT_YET  = 0;
71	localparam OUTPUT_STARTED = 1;
72	
73	localparam CP_FIFO  = 0;
74	localparam PKT_FIFO = 1;
75	
76	reg [5:0]  plcp_bit_cnt;
77	reg [3:0]  service_bit_cnt;
78	reg [18:0] psdu_bit_cnt;        // Maximum number of PSDU bits = 65536*8 = 524288
79	reg [14:0] ofdm_cnt_FSM1;       // Maximum number of OFDM symbols = 3 + ceil((16+524288+6)/26) = 20169
80	
81	//////////////////////////////////////////////////////////////////////////
82	// LEGACY SHORT + LONG PREAMBLE
83	//////////////////////////////////////////////////////////////////////////
84	wire [31:0] l_stf;
85	wire [31:0] l_ltf;
86	reg  [7:0] preamble_addr;
87	l_stf_rom l_stf_rom (
88	    .addr(preamble_addr[3:0]),
89	    .dout(l_stf)
90	);
91	
92	l_ltf_rom l_ltf_rom (
93	    .addr(preamble_addr),
94	    .dout(l_ltf)
95	);
96	
97	//////////////////////////////////////////////////////////////////////////
98	// HT SHORT + LONG PREAMBLE
99	//////////////////////////////////////////////////////////////////////////
100	wire [31:0] ht_stf;
101	wire [31:0] ht_ltf;
102	ht_stf_rom ht_stf_rom (
103	    .addr(preamble_addr[3:0]),
104	    .dout(ht_stf)
105	);
106	
107	ht_ltf_rom ht_ltf_rom (
108	    .addr(preamble_addr[6:0]),
109	    .dout(ht_ltf)
110	);
111	
112	//////////////////////////////////////////////////////////////////////////
113	// Cyclic redundancy check (CRC32) and frame check sequence (FCS) block
114	//////////////////////////////////////////////////////////////////////////
115	wire        crc_en;
116	wire [3:0]  crc_data;
117	wire [31:0] pkt_fcs;
118	reg  [4:0]  pkt_fcs_idx;
119	reg  [3:0]  bram_din_last_nibble;
120	
121	always @(posedge clk)
122	if (reset_int) begin
123	    bram_din_last_nibble <= 0;
124	end else if (bits_enc_fifo_iready) begin
125	    bram_din_last_nibble <= bram_din[63:60];
126	end
127	
128	assign crc_data[0] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[0] : bram_din[(psdu_bit_cnt[5:2] << 2) + 0]) : 0;
129	assign crc_data[1] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[1] : bram_din[(psdu_bit_cnt[5:2] << 2) + 1]) : 0;
130	assign crc_data[2] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[2] : bram_din[(psdu_bit_cnt[5:2] << 2) + 2]) : 0;
131	assign crc_data[3] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[3] : bram_din[(psdu_bit_cnt[5:2] << 2) + 3]) : 0;
132	crc32_tx fcs_inst (
133	    .clk(clk),
134	    .rst(reset_int),
135	    .crc_en(crc_en),
136	    .data_in(crc_data),
137	    .crc_out(pkt_fcs)
138	);
139	assign crc_en = (bits_enc_fifo_iready == 1 && state1 == S1_DATA && state11 == S11_PSDU_DATA && psdu_bit_cnt[1:0] == 2'b11);
140	
141	//////////////////////////////////////////////////////////////////////////
142	// bit source selection and scrambling operation
143	//////////////////////////////////////////////////////////////////////////
144	reg       bit_scram;
145	reg [6:0] data_scram_state;
146	always @* begin
147	    bit_scram = 0;
148	
149	    // Legacy PLCP [rate + reserved + length + parity + tail] and HT PLCP [MCS + length + reserved + short/long GI + CRC + tail] fields
150	    if(state1 == S1_L_SIG || state1 == S1_HT_SIG)
151	        bit_scram = bram_din[plcp_bit_cnt];
152	
153	    // DATA [service + PSDU + CRC + tail + pad] fields
154	    else if(state1 == S1_DATA) begin
155	        // PLCP service field
156	        if(state11 == S11_SERVICE) begin
157	            bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ 0;
158	
159	        // PSDU DATA feild
160	        end else if(state11 == S11_PSDU_DATA) begin
161	            if(psdu_bit_cnt[5:2] == 6'b1111)
162	                bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ bram_din_last_nibble[psdu_bit_cnt[1:0]];
163	            else
164	                bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ bram_din[psdu_bit_cnt[5:0]];
165	
166	        // PSDU CRC field
167	        end else if(state11 == S11_PSDU_CRC) begin
168	            bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ pkt_fcs[pkt_fcs_idx];
169	
170	        // DATA tail field
171	        end else if(state11 == S11_TAIL) begin
172	            bit_scram = 0;
173	
174	        // DATA pad field
175	        end else if(state11 == S11_PAD) begin
176	            bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ 0;
177	        end
178	    end
179	end
180	
181	//////////////////////////////////////////////////////////////////////////
182	// Convolutional encoding
183	//////////////////////////////////////////////////////////////////////////
184	wire       enc_reset;
185	wire       enc_en;
186	wire [1:0] bits_enc;
187	convenc convenc (
188	    .clk(clk),
189	    .rst(enc_reset),
190	    .enc_en(enc_en),
191	    .bit_in(bit_scram),
192	    .bits_out(bits_enc)
193	);
194	assign enc_reset = phy_tx_arest | state1 == S1_WAIT_PKT | plcp_bit_cnt == 23 | plcp_bit_cnt == 47;
195	assign enc_en = state1 >= S1_L_SIG && state11 != S11_RESET && bits_enc_fifo_iready;
196	
197	//////////////////////////////////////////////////////////////////////////
198	// DOT11 TX FINITE STATE MACHINE 1
199	//////////////////////////////////////////////////////////////////////////
200	reg [2:0]  N_BPSC;
201	reg [8:0]  N_DBPS;
202	reg [4:0]  RATE;
203	reg [18:0] PSDU_BIT_LEN;
204	reg        HT_AGGR;
205	reg        S_GI;
206	reg [8:0]  dbps_cnt_FSM1;
207	
208	always @(posedge clk)
209	if (reset_int) begin
210	    bram_addr <= 0;
211	    N_BPSC <= 0;
212	    N_DBPS <= 0;
213	    RATE <= 0;
214	    PSDU_BIT_LEN <= 0;
215	    HT_AGGR <= 0;
216	    S_GI <= 0;
217	    plcp_bit_cnt <= 0;
218	    service_bit_cnt <= 0;
219	    psdu_bit_cnt <= 0;
220	    pkt_fcs_idx <= 0;
221	    dbps_cnt_FSM1 <= 0;
222	    ofdm_cnt_FSM1 <= 0;
223	    data_scram_state <= 0;
224	    state1 <= S1_WAIT_PKT;
225	    state11 <= S11_SERVICE;
226	
227	end else if(bits_enc_fifo_iready == 1) begin
228	    case(state1)
229	    S1_WAIT_PKT: begin
230	        if(phy_tx_start) begin
231	            bram_addr <= 0;
232	            plcp_bit_cnt <= 0;
233	            state1 <= S1_L_SIG;
234	        end
235	    end
236	
237	    S1_L_SIG: begin
238	        plcp_bit_cnt <= plcp_bit_cnt + 1;
239	        if(plcp_bit_cnt == 0) begin
240	            case(bram_din[3:0])
241	                4'b1011: begin  N_BPSC <= 1;  N_DBPS <= 24;  RATE <= 5'b01011; end  //  6 Mbps
242	                4'b1111: begin  N_BPSC <= 1;  N_DBPS <= 36;  RATE <= 5'b01111; end  //  9 Mbps
243	                4'b1010: begin  N_BPSC <= 2;  N_DBPS <= 48;  RATE <= 5'b01010; end  // 12 Mbps
244	                4'b1110: begin  N_BPSC <= 2;  N_DBPS <= 72;  RATE <= 5'b01110; end  // 18 Mbps
245	                4'b1001: begin  N_BPSC <= 4;  N_DBPS <= 96;  RATE <= 5'b01001; end  // 24 Mbps
246	                4'b1101: begin  N_BPSC <= 4;  N_DBPS <= 144; RATE <= 5'b01101; end  // 36 Mbps
247	                4'b1000: begin  N_BPSC <= 6;  N_DBPS <= 192; RATE <= 5'b01000; end  // 48 Mbps
248	                4'b1100: begin  N_BPSC <= 6;  N_DBPS <= 216; RATE <= 5'b01100; end  // 54 Mbps
249	                default: begin  N_BPSC <= 1;  N_DBPS <= 24;  RATE <= 5'b01011; end  //  6 Mbps
250	            endcase
251	            PSDU_BIT_LEN <= {4'd0, bram_din[16:5], 3'd0};
252	            PKT_TYPE <= bram_din[24];
253	
254	        end else if(plcp_bit_cnt == 22) begin
255	            bram_addr <= 1;
256	
257	        end else if(plcp_bit_cnt == 23) begin
258	            ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;
259	            plcp_bit_cnt <= 0;
260	
261	            // HT packet
262	            if(RATE == 5'b01011 && PKT_TYPE == HT) begin
263	                PKT_TYPE <= HT;
264	                state1 <= S1_HT_SIG;
265	
266	            // Legacy packet
267	            end else begin
268	                PKT_TYPE <= LEGACY;
269	                service_bit_cnt <= 0;
270	                data_scram_state <= init_data_scram_state;
271	                dbps_cnt_FSM1 <= 0;
272	
273	                state1 <= S1_DATA;
274	                state11 <= S11_SERVICE;
275	            end
276	        end
277	    end
278	
279	    S1_HT_SIG: begin
280	        plcp_bit_cnt <= plcp_bit_cnt + 1;
281	        if(plcp_bit_cnt == 0) begin
282	            case(bram_din[2:0])
283	                3'b000:  begin  N_BPSC <= 1;  N_DBPS <= 26;  RATE <= 5'b10000; end  //  6.5 Mbps
284	                3'b001:  begin  N_BPSC <= 2;  N_DBPS <= 52;  RATE <= 5'b10001; end  // 13.0 Mbps
285	                3'b010:  begin  N_BPSC <= 2;  N_DBPS <= 78;  RATE <= 5'b10010; end  // 19.5 Mbps
286	                3'b011:  begin  N_BPSC <= 4;  N_DBPS <= 104; RATE <= 5'b10011; end  // 26.0 Mbps
287	                3'b100:  begin  N_BPSC <= 4;  N_DBPS <= 156; RATE <= 5'b10100; end  // 39.0 Mbps
288	                3'b101:  begin  N_BPSC <= 6;  N_DBPS <= 208; RATE <= 5'b10101; end  // 52.0 Mbps
289	                3'b110:  begin  N_BPSC <= 6;  N_DBPS <= 234; RATE <= 5'b10110; end  // 58.5 Mbps
290	                3'b111:  begin  N_BPSC <= 6;  N_DBPS <= 260; RATE <= 5'b10111; end  // 65.0 Mbps
291	                default: begin  N_BPSC <= 1;  N_DBPS <= 26;  RATE <= 5'b10000; end  //  6.5 Mbps
292	            endcase
293	            PSDU_BIT_LEN <= {bram_din[23:8], 3'd0};
294	            HT_AGGR <= bram_din[27];
295	            S_GI <= bram_din[31];
296	        end else if(plcp_bit_cnt == 23) begin
297	            ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;
298	
299	        end else if(plcp_bit_cnt == 47) begin
300	            ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;
301	
302	            service_bit_cnt <= 0;
303	            data_scram_state <= init_data_scram_state;
304	            dbps_cnt_FSM1 <= 0;
305	
306	            state1 <= S1_DATA;
307	            state11 <= S11_SERVICE;
308	        end
309	    end
310	
311	    S1_DATA: begin
312	        data_scram_state <= {data_scram_state[5:0], (data_scram_state[3] ^ data_scram_state[6])};
313	        case(state11)
314	        S11_SERVICE: begin
315	            service_bit_cnt <= service_bit_cnt + 1;
316	            if(service_bit_cnt == 14) begin
317	                bram_addr <= 2;
318	            end else if(service_bit_cnt == 15) begin
319	                psdu_bit_cnt <= 0;
320	                state11 <= S11_PSDU_DATA;
321	            end
322	        end
323	
324	        S11_PSDU_DATA: begin
325	            psdu_bit_cnt <= psdu_bit_cnt + 1;
326	            if((HT_AGGR == 0) && (psdu_bit_cnt == PSDU_BIT_LEN-33))
327	                state11 <= S11_PSDU_CRC;
328	            else if((HT_AGGR == 1) && (psdu_bit_cnt == PSDU_BIT_LEN-1))
329	                state11 <= S11_TAIL;
330	        end
331	
332	        S11_PSDU_CRC: begin
333	            psdu_bit_cnt <= psdu_bit_cnt + 1;
334	            pkt_fcs_idx <= pkt_fcs_idx + 1;
335	            if(psdu_bit_cnt == PSDU_BIT_LEN - 1)
336	                state11 <= S11_TAIL;
337	        end
338	
339	        S11_TAIL: begin
340	            data_scram_state <= data_scram_state;
341	            psdu_bit_cnt <= psdu_bit_cnt + 1;
342	            if(psdu_bit_cnt == PSDU_BIT_LEN + 5)
343	                state11 <= S11_PAD;
344	        end
345	
346	        S11_PAD: begin
347	            psdu_bit_cnt <= psdu_bit_cnt + 1;
348	            if(dbps_cnt_FSM1 == 0) begin
349	                state11 <= S11_RESET;
350	            end
351	        end
352	
353	        S11_RESET: begin
354	        end
355	        endcase
356	
357	        // Update block ram address
358	        if(state11 <= S11_PSDU_DATA && psdu_bit_cnt[5:0] == 6'b111110)
359	            bram_addr <= bram_addr + 1;
360	
361	        // Update dbps and ofdm symbol counters
362	        if(state11 <= S11_PAD) begin
363	            if(dbps_cnt_FSM1 == N_DBPS-1) begin
364	                dbps_cnt_FSM1 <= 0;
365	                ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;
366	            end else begin
367	                dbps_cnt_FSM1 <= dbps_cnt_FSM1 + 1;
368	            end
369	        end
370	    end
371	
372	    default: begin
373	        state1 <= S1_WAIT_PKT;
374	    end
375	    endcase
376	end
377	
378	//////////////////////////////////////////////////////////////////////////
379	// Store scrambed bits into axi stream fifo
380	//////////////////////////////////////////////////////////////////////////
381	wire [1:0]  bits_enc_fifo_idata,  bits_enc_fifo_odata;
382	wire        bits_enc_fifo_ivalid, bits_enc_fifo_ovalid;
383	wire        bits_enc_fifo_iready, bits_enc_fifo_oready;
384	wire [15:0] bits_enc_fifo_space;
385	axi_fifo_bram #(.WIDTH(2), .SIZE(10)) bits_enc_fifo(
386	    .clk(clk), .reset(reset_int), .clear(reset_int),
387	    .i_tdata(bits_enc_fifo_idata), .i_tvalid(bits_enc_fifo_ivalid), .i_tready(bits_enc_fifo_iready),
388	    .o_tdata(bits_enc_fifo_odata), .o_tvalid(bits_enc_fifo_ovalid), .o_tready(bits_enc_fifo_oready),
389	    .space(bits_enc_fifo_space), .occupied()
390	);
391	assign bits_enc_fifo_idata  = bits_enc;
392	assign bits_enc_fifo_ivalid = state1 != S1_WAIT_PKT && state11 < S11_RESET;
393	assign bits_enc_fifo_oready = (state2 == S2_PUNC_INTERLV && bits_enc_fifo_ovalid == 1 && (enc_pos == 1 || (|punc_info == 1)));
394	
395	//////////////////////////////////////////////////////////////////////////
396	// Bit puncturing and bit interleaving
397	//////////////////////////////////////////////////////////////////////////
398	// Puncturing and interleaving index look up table
399	reg  [14:0] ofdm_cnt_FSM2;
400	reg  [8:0]  dbps_cnt_FSM2;
401	wire [1:0]  punc_info;
402	wire [17:0] interlv_addrs;
403	punc_interlv_lut punc_interlv_lut(
404	    .rate(PKT_TYPE == LEGACY ? (ofdm_cnt_FSM2 > 0 ? RATE : 5'b01011) : (ofdm_cnt_FSM2 > 2 ? RATE : 5'b01011)),
405	    .idx_i(dbps_cnt_FSM2),
406	    .idx_o(interlv_addrs),
407	    .punc_o(punc_info)
408	);
409	
410	// This is a RAM module for holding convolutionally encoded, punctured and interleaved bits.
411	// Bit puncturing is implicitly carried out, such that punc_interlv_lut provides write address along with puncturing ON/OFF signal
412	reg        enc_pos;
413	wire       bits_ram_en;
414	wire       punc_bit;
415	wire [8:0] bits_ram_waddr;
416	reg  [5:0] mod_addr;
417	wire [5:0] bits_to_mod;
418	ram_simo #(.DEPTH(52)) bits_ram(
419	    .clk(clk),
420	    .waddr(bits_ram_waddr),
421	    .raddr(mod_addr),
422	    .wen(bits_ram_en),
423	    .data_i(punc_bit),
424	    .data_o(bits_to_mod)
425	);
426	assign bits_ram_waddr = enc_pos == 1 ? interlv_addrs[17:9] : (punc_info[0] == 0 ? interlv_addrs[8:0] : interlv_addrs[17:9]);
427	assign bits_ram_en = (state2 == S2_PUNC_INTERLV);
428	assign punc_bit = enc_pos == 1 ? bits_enc_fifo_odata[0] : (punc_info[0] == 0 ? bits_enc_fifo_odata[1] : bits_enc_fifo_odata[0]);
429	
430	//////////////////////////////////////////////////////////////////////////
431	// Bits modulation
432	//////////////////////////////////////////////////////////////////////////
433	// BPSK, QPSK, 16-QAM and 64-QAM modulation
434	wire [31:0] mod_IQ;
435	modulation modulation(
436	    .N_BPSC(PKT_TYPE == LEGACY ? (ofdm_cnt_FSM2 > 0 ? N_BPSC : 3'd1) : (ofdm_cnt_FSM2 > 2 ? N_BPSC : 3'd1)),
437	    .bits_in(bits_to_mod),
438	    .IQ(mod_IQ)
439	);
440	
441	//////////////////////////////////////////////////////////////////////////
442	// PILOT, DC (0Hz) and sideband(SB)
443	//////////////////////////////////////////////////////////////////////////
444	reg  [31:0] pilot_iq [3:0];
445	reg  [6:0]  pilot_scram_state;
446	reg  [3:0]  ht_polarity;
447	wire        pilot_gain = pilot_scram_state[6] ^ pilot_scram_state[3] ^ 0;
448	wire [31:0] DC_SB_IQ = {16'h0000, 16'h0000};
449	
450	//////////////////////////////////////////////////////////////////////////
451	// Inverse Fast Fourier Transform (IFFT)
452	//////////////////////////////////////////////////////////////////////////
453	reg [31:0] ifft_iq;
454	reg [7:0]  iq_cnt;
455	always @* begin
456	    ifft_iq = 0;
457	    if(state2 == S2_MOD_IFFT_INPUT) begin
458	        if(iq_cnt == 0 || ((PKT_TYPE == LEGACY || PKT_TYPE == HT && ofdm_cnt_FSM2 <= 2) && iq_cnt >= 27 && iq_cnt < 38) || (PKT_TYPE == HT && ofdm_cnt_FSM2 > 2 && iq_cnt >= 29 && iq_cnt < 36)) begin
459	            ifft_iq = DC_SB_IQ;
460	        end else if(iq_cnt == 7) begin
461	            ifft_iq = pilot_iq[2];
462	        end else if(iq_cnt == 21) begin
463	            ifft_iq = pilot_iq[3];
464	        end else if(iq_cnt == 43) begin
465	            ifft_iq = pilot_iq[0];
466	        end else if(iq_cnt == 57) begin
467	            ifft_iq = pilot_iq[1];
468	        end else if(iq_cnt < 64) begin
469	            if(PKT_TYPE == HT && (ofdm_cnt_FSM2 == 1 || ofdm_cnt_FSM2 == 2))
470	                ifft_iq = {mod_IQ[15:0], mod_IQ[31:16]};
471	            else
472	                ifft_iq = mod_IQ;
473	        end
474	    end
475	end
476	
477	reg         ifft_ce;
478	wire        ifft_o_sync;
479	wire [31:0] ifft_o_result;
480	ifftmain ifft64(
481	    .i_clk(clk), .i_reset(reset_int),
482	    .i_ce(ifft_ce),
483	    .i_sample(ifft_iq),
484	    .o_result(ifft_o_result),
485	    .o_sync(ifft_o_sync)
486	);
487	
488	//////////////////////////////////////////////////////////////////////////
489	// DOT11 TX FINITE STATE MACHINE 2
490	//////////////////////////////////////////////////////////////////////////
491	wire [8:0]  dbps_size;
492	
493	always @(posedge clk)
494	if (reset_int) begin
495	    dbps_cnt_FSM2 <= 0;
496	    enc_pos <= 0;
497	    ofdm_cnt_FSM2 <= 0;
498	    iq_cnt <= 0;
499	    ifft_ce <= 0;
500	    mod_addr <= 0;
501	    pilot_scram_state <= init_pilot_scram_state;
502	    ht_polarity <= 4'b1000;
503	    state2 <= S2_PUNC_INTERLV;
504	
505	end else begin
506	    case(state2)
507	    S2_PUNC_INTERLV: begin
508	        if(pkt_fifo_space > 63 && CP_fifo_space > 15 && bits_enc_fifo_ovalid == 1) begin
509	            // The encoding position is shifted only if encoded bits are not punctured
510	            if(|punc_info == 0)
511	                enc_pos <= ~enc_pos;
512	
513	            // If encoding position is on the second place or if encoded bits are punctured
514	            if(enc_pos == 1 || |punc_info == 1) begin
515	                if(dbps_cnt_FSM2 == dbps_size-1) begin
516	                    dbps_cnt_FSM2 <= 0;
517	                    state2 <= S2_PILOT_DC_SB;
518	
519	                end else begin
520	                    dbps_cnt_FSM2 <= dbps_cnt_FSM2 + 1;
521	                end
522	            end
523	        end
524	    end
525	
526	    S2_PILOT_DC_SB: begin
527	        if(PKT_TYPE == HT && ofdm_cnt_FSM2 > 2) begin
528	            if(ht_polarity[0] ^ pilot_gain == 0)
529	                pilot_iq[0] <= {16'h4000, 16'h0000};
530	            else
531	                pilot_iq[0] <= {16'hC000, 16'h0000};
532	
533	            if(ht_polarity[1] ^ pilot_gain == 0)
534	                pilot_iq[1] <= {16'h4000, 16'h0000};
535	            else
536	                pilot_iq[1] <= {16'hC000, 16'h0000};
537	
538	            if(ht_polarity[2] ^ pilot_gain == 0)
539	                pilot_iq[2] <= {16'h4000, 16'h0000};
540	            else
541	                pilot_iq[2] <= {16'hC000, 16'h0000};
542	
543	            if(ht_polarity[3] ^ pilot_gain == 0)
544	                pilot_iq[3] <= {16'h4000, 16'h0000};
545	            else
546	                pilot_iq[3] <= {16'hC000, 16'h0000};
547	
548	            ht_polarity <= {ht_polarity[0], ht_polarity[3:1]};
549	        end else begin
550	            if(pilot_gain == 0) begin
551	                pilot_iq[0] <= {16'h4000, 16'h0000};
552	                pilot_iq[1] <= {16'h4000, 16'h0000};
553	                pilot_iq[2] <= {16'h4000, 16'h0000};
554	                pilot_iq[3] <= {16'hC000, 16'h0000};
555	            end else begin
556	                pilot_iq[0] <= {16'hC000, 16'h0000};
557	                pilot_iq[1] <= {16'hC000, 16'h0000};
558	                pilot_iq[2] <= {16'hC000, 16'h0000};
559	                pilot_iq[3] <= {16'h4000, 16'h0000};
560	            end
561	        end
562	        pilot_scram_state <= {pilot_scram_state[5:0], (pilot_scram_state[3] ^ pilot_scram_state[6])};
563	
564	        iq_cnt <= 0;
565	        ifft_ce <= 1;
566	        state2 <= S2_MOD_IFFT_INPUT;
567	    end
568	
569	    S2_MOD_IFFT_INPUT: begin
570	        if(iq_cnt < 63) begin
571	            if(PKT_TYPE == HT && ofdm_cnt_FSM2 > 2) begin
572	                if(iq_cnt < 6)
573	                    mod_addr <= iq_cnt[5:0] + 26;
574	                else if(iq_cnt < 20)
575	                    mod_addr <= iq_cnt[5:0] + 25;
576	                else if(iq_cnt < 28)
577	                    mod_addr <= iq_cnt[5:0] + 24;
578	                else if(iq_cnt < 42)
579	                    mod_addr <= iq_cnt[5:0] - 35;
580	                else if(iq_cnt < 56)
581	                    mod_addr <= iq_cnt[5:0] - 36;
582	                else if(iq_cnt < 63)
583	                    mod_addr <= iq_cnt[5:0] - 37;
584	            end else begin
585	                if(iq_cnt < 6)
586	                    mod_addr <= iq_cnt[5:0] + 24;
587	                else if(iq_cnt < 20)
588	                    mod_addr <= iq_cnt[5:0] + 23;
589	                else if(iq_cnt < 28)
590	                    mod_addr <= iq_cnt[5:0] + 22;
591	                else if(iq_cnt < 42)
592	                    mod_addr <= iq_cnt[5:0] - 37;
593	                else if(iq_cnt < 56)
594	                    mod_addr <= iq_cnt[5:0] - 38;
595	                else if(iq_cnt < 63)
596	                    mod_addr <= iq_cnt[5:0] - 39;
597	            end
598	
599	            iq_cnt <= iq_cnt + 1;
600	
601	        end else begin
602	            ifft_ce <= 0;
603	            ofdm_cnt_FSM2 <= ofdm_cnt_FSM2 + 1;
604	            state2 <= S2_RESET;
605	        end
606	    end
607	
608	    S2_RESET: begin
609	        // This is not the last OFDM symbol processed
610	        if(ofdm_cnt_FSM2 < ofdm_cnt_FSM1) begin
611			    state2 <= S2_PUNC_INTERLV;
612	        end else if(state11 == S11_RESET) begin
613	            if(pkt_fifo_space > 2 && CP_fifo_space > 2)
614	                ifft_ce <= 1;
615	            else
616	                ifft_ce <= 0;
617	        end
618	    end
619	
620	    default: begin
621	        state2 <= S2_PUNC_INTERLV;
622	    end
623	    endcase
624	end
625	assign dbps_size = PKT_TYPE == LEGACY ? (ofdm_cnt_FSM2 > 0 ? N_DBPS : 24) : (ofdm_cnt_FSM2 > 2 ? N_DBPS : 24);
626	
627	//////////////////////////////////////////////////////////////////////////
628	// Count number of [pkt/CP] IQ samples to send
629	//////////////////////////////////////////////////////////////////////////
630	reg        ifft_status;
631	reg        ifft_ce_reg;
632	reg [31:0] ifft_o_result_reg;
633	reg [5:0]  ifft_o_iq_cnt;
634	reg [14:0] ifft_o_sync_cnt;
635	reg [20:0] nof_iq2send;			// 480 + 20169*80 = 1614000 IQ samples
636	always @(posedge clk)
637	if (reset_int) begin
638	    ifft_o_iq_cnt <= 0;
639	    ifft_o_sync_cnt <= 0;
640	    ifft_status <= NO_OUTPUT_YET;
641	    nof_iq2send <= 320;
642	
643	end else begin
644	    ifft_o_result_reg <= ifft_o_result;
645	    ifft_ce_reg <= ifft_ce;
646	
647	    if(ifft_o_sync == 1) begin
648	        ifft_o_sync_cnt <= ifft_o_sync_cnt + 1;
649	        // The moment ifft outputs the first result, we change the status
650	        if(ifft_status == NO_OUTPUT_YET)
651	            ifft_status <= OUTPUT_STARTED;
652	    end
653	
654	    // IFFT output counter
655	    if(ifft_status == OUTPUT_STARTED && ifft_ce == 1)
656	        ifft_o_iq_cnt <= ifft_o_iq_cnt + 1;
657	
658	    // update number of IQ samples to send
659	    if(state2 == S2_PILOT_DC_SB) begin
660	        if(PKT_TYPE == HT) begin
661	            if(nof_iq2send == 480)
662	                nof_iq2send <= nof_iq2send + 240;
663	            else if(nof_iq2send < 480 || S_GI == 0)
664	                nof_iq2send <= nof_iq2send + 80;
665	            else
666	                nof_iq2send <= nof_iq2send + 72;
667	        end else begin
668	            nof_iq2send <= nof_iq2send + 80;
669	        end
670	    end
671	end
672	
673	//////////////////////////////////////////////////////////////////////////
674	// Cyclic Prefix IFFT output -> Axi stream fifo
675	//////////////////////////////////////////////////////////////////////////
676	wire [31:0] CP_fifo_idata,  CP_fifo_odata;
677	wire        CP_fifo_ivalid, CP_fifo_ovalid;
678	wire        CP_fifo_iready, CP_fifo_oready;
679	wire [15:0] CP_fifo_space;
680	axi_fifo_bram #(.WIDTH(32), .SIZE(6)) CP_fifo(
681	    .clk(clk), .reset(reset_int), .clear(reset_int),
682	    .i_tdata(CP_fifo_idata), .i_tvalid(CP_fifo_ivalid), .i_tready(CP_fifo_iready),
683	    .o_tdata(CP_fifo_odata), .o_tvalid(CP_fifo_ovalid), .o_tready(CP_fifo_oready),
684	    .space(CP_fifo_space), .occupied()
685	);
686	assign CP_fifo_idata  = ifft_o_result_reg;
687	assign CP_fifo_ivalid = (S_GI == 1 && ifft_o_sync_cnt > 3) ? (ifft_o_iq_cnt[5:3] == 3'b111 ? ifft_ce_reg : 0) : (ifft_o_iq_cnt[5:4] == 2'b11 ? ifft_ce_reg : 0);
688	assign CP_fifo_oready = (state3 == S3_L_SIG || state3 == S3_HT_SIG || state3 == S3_DATA) && fifo_turn == CP_FIFO ? result_iq_ready : 0;
689	
690	//////////////////////////////////////////////////////////////////////////
691	// Packet IFFT output -> Axi stream fifo
692	//////////////////////////////////////////////////////////////////////////
693	wire [31:0] pkt_fifo_idata,  pkt_fifo_odata;
694	wire        pkt_fifo_ivalid, pkt_fifo_ovalid;
695	wire        pkt_fifo_iready, pkt_fifo_oready;
696	wire [15:0] pkt_fifo_space;
697	axi_fifo_bram #(.WIDTH(32), .SIZE(8)) pkt_fifo(
698	    .clk(clk), .reset(reset_int), .clear(reset_int),
699	    .i_tdata(pkt_fifo_idata), .i_tvalid(pkt_fifo_ivalid), .i_tready(pkt_fifo_iready),
700	    .o_tdata(pkt_fifo_odata), .o_tvalid(pkt_fifo_ovalid), .o_tready(pkt_fifo_oready),
701	    .space(pkt_fifo_space), .occupied()
702	);
703	assign pkt_fifo_idata  = ifft_o_result_reg;
704	assign pkt_fifo_ivalid = ifft_status == OUTPUT_STARTED ? ifft_ce_reg : 0;
705	assign pkt_fifo_oready = (state3 == S3_L_SIG || state3 == S3_HT_SIG || state3 == S3_DATA) && fifo_turn == PKT_FIFO ? result_iq_ready : 0;
706	
707	//////////////////////////////////////////////////////////////////////////
708	// Count number of [pkt/CP] IQ samples sent
709	//////////////////////////////////////////////////////////////////////////
710	reg        fifo_turn;
711	reg [20:0] pkt_iq_sent;
712	reg [18:0] CP_iq_sent;
713	always @(posedge clk)
714	if (reset_int) begin
715	    fifo_turn   <= PKT_FIFO;
716	    pkt_iq_sent <= 0;
717	    CP_iq_sent  <= 0;
718	
719	end else begin
720	    if(result_iq_ready == 1 && result_iq_valid == 1) begin
721	        if(fifo_turn == PKT_FIFO) begin
722	            if(pkt_iq_sent[5:0] == 6'b111111 && |pkt_iq_sent[15:8] == 1)
723	                fifo_turn <= CP_FIFO;
724	            pkt_iq_sent   <= pkt_iq_sent + 1;
725	        end else if(fifo_turn == CP_FIFO) begin
726	            if((pkt_iq_sent < 640 && CP_iq_sent[3:0] == 4'b1111) || (S_GI == 0 && CP_iq_sent[3:0] == 4'b1111) || (S_GI == 1 && pkt_iq_sent >= 640 && CP_iq_sent[2:0] == 3'b111))
727	                fifo_turn <= PKT_FIFO;
728	            CP_iq_sent    <= CP_iq_sent + 1;
729	        end
730	    end
731	end
732	
733	//////////////////////////////////////////////////////////////////////////
734	// DOT11 TX FINITE STATE MACHINE 3
735	//////////////////////////////////////////////////////////////////////////
736	always @(posedge clk)
737	if (reset_int) begin
738	    preamble_addr <= 0;
739	    phy_tx_done <= 0;
740	    FSM3_reset <= 0;
741	
742	    state3 <= S3_WAIT_PKT;
743	
744	end else if(result_iq_ready == 1) begin
745	    case(state3)
746	    S3_WAIT_PKT: begin
747	        if(phy_tx_start) begin
748	            preamble_addr <= 0;
749	            state3 <= S3_L_STF;
750	        end
751	    end
752	
753	    S3_L_STF: begin
754	        // Legacy short preamble contains 10*16 = 160 samples
755	        if(preamble_addr < 159) begin
756	            preamble_addr <= preamble_addr + 1;
757	        end else begin
758	            preamble_addr <= 0;
759	            state3 <= S3_L_LTF;
760	        end
761	
762	        // Send "OPERATION STARTED" message to upper layer
763	        if(preamble_addr == 0)
764	            phy_tx_started <= 1;
765	        else
766	            phy_tx_started <= 0;
767	    end
768	
769	    S3_L_LTF: begin
770	        // Legacy long preamble contains 160 samples
771	        if(preamble_addr < 159) begin
772	            preamble_addr <= preamble_addr + 1;
773	
774	        end else begin
775	            state3 <= S3_L_SIG;
776	        end
777	    end
778	
779	    S3_L_SIG: begin
780	        // Legacy SIGNAL contains 80 samples
781	        if(pkt_iq_sent == 383 && CP_iq_sent == 16) begin
782	            if(PKT_TYPE == LEGACY)
783	                state3 <= S3_DATA;
784	            else
785	                state3 <= S3_HT_SIG;
786	        end
787	    end
788	
789	    S3_HT_SIG: begin
790	        // HT SIGNAL contains 160 samples
791	        if(pkt_iq_sent == 511 && CP_iq_sent == 48) begin
792	            preamble_addr <= 0;
793	            state3 <= S3_HT_STF;
794	        end
795	    end
796	
797	    S3_HT_STF: begin
798	        // HT short preamble contains 5*16 = 80 samples
799	        if(preamble_addr < 79) begin
800	            preamble_addr <= preamble_addr + 1;
801	        end else begin
802	            preamble_addr <= 0;
803	            state3 <= S3_HT_LTF;
804	        end
805	    end
806	
807	    S3_HT_LTF: begin
808	        // HT long preamble contains 80 samples
809	        if(preamble_addr < 79) begin
810	            preamble_addr <= preamble_addr + 1;
811	
812	        end else begin
813	            state3 <= S3_DATA;
814	        end
815	    end
816	
817	    S3_DATA: begin
818	        if((pkt_iq_sent + {2'b00, CP_iq_sent}) == nof_iq2send-2) begin
819	            phy_tx_done <= 1;
820	            FSM3_reset <= 1;
821	        end
822	    end
823	    endcase
824	end
825	
826	assign result_i        = state3 == S3_L_STF ? l_stf[31:16] : (state3 == S3_L_LTF ? l_ltf[31:16] : (state3 == S3_HT_STF ? ht_stf[31:16] : (state3 == S3_HT_LTF ? ht_ltf[31:16] : (fifo_turn == PKT_FIFO ? pkt_fifo_odata[31:16] : CP_fifo_odata[31:16]))));
827	assign result_q        = state3 == S3_L_STF ? l_stf[15:0]  : (state3 == S3_L_LTF ? l_ltf[15:0]  : (state3 == S3_HT_STF ? ht_stf[15:0]  : (state3 == S3_HT_LTF ? ht_ltf[15:0]  : (fifo_turn == PKT_FIFO ? pkt_fifo_odata[15:0]  : CP_fifo_odata[15:0]))));
828	assign result_iq_valid = state3 == S3_L_STF || state3 == S3_L_LTF || state3 == S3_HT_STF || state3 == S3_HT_LTF ? 1 : (fifo_turn == PKT_FIFO ? pkt_fifo_ovalid : CP_fifo_ovalid);
829	
830	endmodule
831

file.content:
/*
 * dot11_tx - TODO
 *
 * Michael Tetemke Mehari mehari.michael@gmail.com
 * Xianjun Jiao xianjun.jiao@ugent.be
 */

`include "openofdm_tx_pre_def.v"

module dot11_tx
(
  input  wire        clk,
  input  wire        phy_tx_arest,

  input  wire        phy_tx_start,
  output reg         phy_tx_done,
  output reg         phy_tx_started,

  input  wire [6:0]  init_pilot_scram_state,
  input  wire [6:0]  init_data_scram_state,

  input  wire [63:0] bram_din,
  output reg  [9:0]  bram_addr,

  input  wire        result_iq_ready,
  output wire        result_iq_valid,
  output wire [15:0] result_i,
  output wire [15:0] result_q
);

reg  FSM3_reset;        // Reset after transmiting a whole packet
wire reset_int = phy_tx_arest | FSM3_reset;

// Data collection states
reg [1:0] state1;
localparam S1_WAIT_PKT = 0;
localparam S1_L_SIG    = 1;
localparam S1_HT_SIG   = 2;
localparam S1_DATA     = 3;
reg [2:0] state11;
localparam S11_SERVICE   = 0;
localparam S11_PSDU_DATA = 1;
localparam S11_PSDU_CRC  = 2;
localparam S11_TAIL      = 3;
localparam S11_PAD       = 4;
localparam S11_RESET     = 5;

// IQ sample generation states
reg [1:0] state2;
localparam S2_PUNC_INTERLV   = 0;
localparam S2_PILOT_DC_SB    = 1;
localparam S2_MOD_IFFT_INPUT = 2;
localparam S2_RESET          = 3;

// IQ sample forwarding states
reg [2:0] state3;
localparam S3_WAIT_PKT = 0;
localparam S3_L_STF    = 1;
localparam S3_L_LTF    = 2;
localparam S3_L_SIG    = 3;
localparam S3_HT_SIG   = 4;
localparam S3_HT_STF   = 5;
localparam S3_HT_LTF   = 6;
localparam S3_DATA     = 7;

reg PKT_TYPE;
localparam LEGACY = 0;
localparam HT     = 1;

localparam NO_OUTPUT_YET  = 0;
localparam OUTPUT_STARTED = 1;

localparam CP_FIFO  = 0;
localparam PKT_FIFO = 1;

reg [5:0]  plcp_bit_cnt;
reg [3:0]  service_bit_cnt;
reg [18:0] psdu_bit_cnt;        // Maximum number of PSDU bits = 65536*8 = 524288
reg [14:0] ofdm_cnt_FSM1;       // Maximum number of OFDM symbols = 3 + ceil((16+524288+6)/26) = 20169

//////////////////////////////////////////////////////////////////////////
// LEGACY SHORT + LONG PREAMBLE
//////////////////////////////////////////////////////////////////////////
wire [31:0] l_stf;
wire [31:0] l_ltf;
reg  [7:0] preamble_addr;
l_stf_rom l_stf_rom (
    .addr(preamble_addr[3:0]),
    .dout(l_stf)
);

l_ltf_rom l_ltf_rom (
    .addr(preamble_addr),
    .dout(l_ltf)
);

//////////////////////////////////////////////////////////////////////////
// HT SHORT + LONG PREAMBLE
//////////////////////////////////////////////////////////////////////////
wire [31:0] ht_stf;
wire [31:0] ht_ltf;
ht_stf_rom ht_stf_rom (
    .addr(preamble_addr[3:0]),
    .dout(ht_stf)
);

ht_ltf_rom ht_ltf_rom (
    .addr(preamble_addr[6:0]),
    .dout(ht_ltf)
);

//////////////////////////////////////////////////////////////////////////
// Cyclic redundancy check (CRC32) and frame check sequence (FCS) block
//////////////////////////////////////////////////////////////////////////
wire        crc_en;
wire [3:0]  crc_data;
wire [31:0] pkt_fcs;
reg  [4:0]  pkt_fcs_idx;
reg  [3:0]  bram_din_last_nibble;

always @(posedge clk)
if (reset_int) begin
    bram_din_last_nibble <= 0;
end else if (bits_enc_fifo_iready) begin
    bram_din_last_nibble <= bram_din[63:60];
end

assign crc_data[0] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[0] : bram_din[(psdu_bit_cnt[5:2] << 2) + 0]) : 0;
assign crc_data[1] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[1] : bram_din[(psdu_bit_cnt[5:2] << 2) + 1]) : 0;
assign crc_data[2] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[2] : bram_din[(psdu_bit_cnt[5:2] << 2) + 2]) : 0;
assign crc_data[3] = (state1 == S1_DATA && state11 == S11_PSDU_DATA) ? (psdu_bit_cnt[5:0] == 6'b111111 ? bram_din_last_nibble[3] : bram_din[(psdu_bit_cnt[5:2] << 2) + 3]) : 0;
crc32_tx fcs_inst (
    .clk(clk),
    .rst(reset_int),
    .crc_en(crc_en),
    .data_in(crc_data),
    .crc_out(pkt_fcs)
);
assign crc_en = (bits_enc_fifo_iready == 1 && state1 == S1_DATA && state11 == S11_PSDU_DATA && psdu_bit_cnt[1:0] == 2'b11);

//////////////////////////////////////////////////////////////////////////
// bit source selection and scrambling operation
//////////////////////////////////////////////////////////////////////////
reg       bit_scram;
reg [6:0] data_scram_state;
always @* begin
    bit_scram = 0;

    // Legacy PLCP [rate + reserved + length + parity + tail] and HT PLCP [MCS + length + reserved + short/long GI + CRC + tail] fields
    if(state1 == S1_L_SIG || state1 == S1_HT_SIG)
        bit_scram = bram_din[plcp_bit_cnt];

    // DATA [service + PSDU + CRC + tail + pad] fields
    else if(state1 == S1_DATA) begin
        // PLCP service field
        if(state11 == S11_SERVICE) begin
            bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ 0;

        // PSDU DATA feild
        end else if(state11 == S11_PSDU_DATA) begin
            if(psdu_bit_cnt[5:2] == 6'b1111)
                bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ bram_din_last_nibble[psdu_bit_cnt[1:0]];
            else
                bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ bram_din[psdu_bit_cnt[5:0]];

        // PSDU CRC field
        end else if(state11 == S11_PSDU_CRC) begin
            bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ pkt_fcs[pkt_fcs_idx];

        // DATA tail field
        end else if(state11 == S11_TAIL) begin
            bit_scram = 0;

        // DATA pad field
        end else if(state11 == S11_PAD) begin
            bit_scram = data_scram_state[6] ^ data_scram_state[3] ^ 0;
        end
    end
end

//////////////////////////////////////////////////////////////////////////
// Convolutional encoding
//////////////////////////////////////////////////////////////////////////
wire       enc_reset;
wire       enc_en;
wire [1:0] bits_enc;
convenc convenc (
    .clk(clk),
    .rst(enc_reset),
    .enc_en(enc_en),
    .bit_in(bit_scram),
    .bits_out(bits_enc)
);
assign enc_reset = phy_tx_arest | state1 == S1_WAIT_PKT | plcp_bit_cnt == 23 | plcp_bit_cnt == 47;
assign enc_en = state1 >= S1_L_SIG && state11 != S11_RESET && bits_enc_fifo_iready;

//////////////////////////////////////////////////////////////////////////
// DOT11 TX FINITE STATE MACHINE 1
//////////////////////////////////////////////////////////////////////////
reg [2:0]  N_BPSC;
reg [8:0]  N_DBPS;
reg [4:0]  RATE;
reg [18:0] PSDU_BIT_LEN;
reg        HT_AGGR;
reg        S_GI;
reg [8:0]  dbps_cnt_FSM1;

always @(posedge clk)
if (reset_int) begin
    bram_addr <= 0;
    N_BPSC <= 0;
    N_DBPS <= 0;
    RATE <= 0;
    PSDU_BIT_LEN <= 0;
    HT_AGGR <= 0;
    S_GI <= 0;
    plcp_bit_cnt <= 0;
    service_bit_cnt <= 0;
    psdu_bit_cnt <= 0;
    pkt_fcs_idx <= 0;
    dbps_cnt_FSM1 <= 0;
    ofdm_cnt_FSM1 <= 0;
    data_scram_state <= 0;
    state1 <= S1_WAIT_PKT;
    state11 <= S11_SERVICE;

end else if(bits_enc_fifo_iready == 1) begin
    case(state1)
    S1_WAIT_PKT: begin
        if(phy_tx_start) begin
            bram_addr <= 0;
            plcp_bit_cnt <= 0;
            state1 <= S1_L_SIG;
        end
    end

    S1_L_SIG: begin
        plcp_bit_cnt <= plcp_bit_cnt + 1;
        if(plcp_bit_cnt == 0) begin
            case(bram_din[3:0])
                4'b1011: begin  N_BPSC <= 1;  N_DBPS <= 24;  RATE <= 5'b01011; end  //  6 Mbps
                4'b1111: begin  N_BPSC <= 1;  N_DBPS <= 36;  RATE <= 5'b01111; end  //  9 Mbps
                4'b1010: begin  N_BPSC <= 2;  N_DBPS <= 48;  RATE <= 5'b01010; end  // 12 Mbps
                4'b1110: begin  N_BPSC <= 2;  N_DBPS <= 72;  RATE <= 5'b01110; end  // 18 Mbps
                4'b1001: begin  N_BPSC <= 4;  N_DBPS <= 96;  RATE <= 5'b01001; end  // 24 Mbps
                4'b1101: begin  N_BPSC <= 4;  N_DBPS <= 144; RATE <= 5'b01101; end  // 36 Mbps
                4'b1000: begin  N_BPSC <= 6;  N_DBPS <= 192; RATE <= 5'b01000; end  // 48 Mbps
                4'b1100: begin  N_BPSC <= 6;  N_DBPS <= 216; RATE <= 5'b01100; end  // 54 Mbps
                default: begin  N_BPSC <= 1;  N_DBPS <= 24;  RATE <= 5'b01011; end  //  6 Mbps
            endcase
            PSDU_BIT_LEN <= {4'd0, bram_din[16:5], 3'd0};
            PKT_TYPE <= bram_din[24];

        end else if(plcp_bit_cnt == 22) begin
            bram_addr <= 1;

        end else if(plcp_bit_cnt == 23) begin
            ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;
            plcp_bit_cnt <= 0;

            // HT packet
            if(RATE == 5'b01011 && PKT_TYPE == HT) begin
                PKT_TYPE <= HT;
                state1 <= S1_HT_SIG;

            // Legacy packet
            end else begin
                PKT_TYPE <= LEGACY;
                service_bit_cnt <= 0;
                data_scram_state <= init_data_scram_state;
                dbps_cnt_FSM1 <= 0;

                state1 <= S1_DATA;
                state11 <= S11_SERVICE;
            end
        end
    end

    S1_HT_SIG: begin
        plcp_bit_cnt <= plcp_bit_cnt + 1;
        if(plcp_bit_cnt == 0) begin
            case(bram_din[2:0])
                3'b000:  begin  N_BPSC <= 1;  N_DBPS <= 26;  RATE <= 5'b10000; end  //  6.5 Mbps
                3'b001:  begin  N_BPSC <= 2;  N_DBPS <= 52;  RATE <= 5'b10001; end  // 13.0 Mbps
                3'b010:  begin  N_BPSC <= 2;  N_DBPS <= 78;  RATE <= 5'b10010; end  // 19.5 Mbps
                3'b011:  begin  N_BPSC <= 4;  N_DBPS <= 104; RATE <= 5'b10011; end  // 26.0 Mbps
                3'b100:  begin  N_BPSC <= 4;  N_DBPS <= 156; RATE <= 5'b10100; end  // 39.0 Mbps
                3'b101:  begin  N_BPSC <= 6;  N_DBPS <= 208; RATE <= 5'b10101; end  // 52.0 Mbps
                3'b110:  begin  N_BPSC <= 6;  N_DBPS <= 234; RATE <= 5'b10110; end  // 58.5 Mbps
                3'b111:  begin  N_BPSC <= 6;  N_DBPS <= 260; RATE <= 5'b10111; end  // 65.0 Mbps
                default: begin  N_BPSC <= 1;  N_DBPS <= 26;  RATE <= 5'b10000; end  //  6.5 Mbps
            endcase
            PSDU_BIT_LEN <= {bram_din[23:8], 3'd0};
            HT_AGGR <= bram_din[27];
            S_GI <= bram_din[31];
        end else if(plcp_bit_cnt == 23) begin
            ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;

        end else if(plcp_bit_cnt == 47) begin
            ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;

            service_bit_cnt <= 0;
            data_scram_state <= init_data_scram_state;
            dbps_cnt_FSM1 <= 0;

            state1 <= S1_DATA;
            state11 <= S11_SERVICE;
        end
    end

    S1_DATA: begin
        data_scram_state <= {data_scram_state[5:0], (data_scram_state[3] ^ data_scram_state[6])};
        case(state11)
        S11_SERVICE: begin
            service_bit_cnt <= service_bit_cnt + 1;
            if(service_bit_cnt == 14) begin
                bram_addr <= 2;
            end else if(service_bit_cnt == 15) begin
                psdu_bit_cnt <= 0;
                state11 <= S11_PSDU_DATA;
            end
        end

        S11_PSDU_DATA: begin
            psdu_bit_cnt <= psdu_bit_cnt + 1;
            if((HT_AGGR == 0) && (psdu_bit_cnt == PSDU_BIT_LEN-33))
                state11 <= S11_PSDU_CRC;
            else if((HT_AGGR == 1) && (psdu_bit_cnt == PSDU_BIT_LEN-1))
                state11 <= S11_TAIL;
        end

        S11_PSDU_CRC: begin
            psdu_bit_cnt <= psdu_bit_cnt + 1;
            pkt_fcs_idx <= pkt_fcs_idx + 1;
            if(psdu_bit_cnt == PSDU_BIT_LEN - 1)
                state11 <= S11_TAIL;
        end

        S11_TAIL: begin
            data_scram_state <= data_scram_state;
            psdu_bit_cnt <= psdu_bit_cnt + 1;
            if(psdu_bit_cnt == PSDU_BIT_LEN + 5)
                state11 <= S11_PAD;
        end

        S11_PAD: begin
            psdu_bit_cnt <= psdu_bit_cnt + 1;
            if(dbps_cnt_FSM1 == 0) begin
                state11 <= S11_RESET;
            end
        end

        S11_RESET: begin
        end
        endcase

        // Update block ram address
        if(state11 <= S11_PSDU_DATA && psdu_bit_cnt[5:0] == 6'b111110)
            bram_addr <= bram_addr + 1;

        // Update dbps and ofdm symbol counters
        if(state11 <= S11_PAD) begin
            if(dbps_cnt_FSM1 == N_DBPS-1) begin
                dbps_cnt_FSM1 <= 0;
                ofdm_cnt_FSM1 <= ofdm_cnt_FSM1 + 1;
            end else begin
                dbps_cnt_FSM1 <= dbps_cnt_FSM1 + 1;
            end
        end
    end

    default: begin
        state1 <= S1_WAIT_PKT;
    end
    endcase
end

//////////////////////////////////////////////////////////////////////////
// Store scrambed bits into axi stream fifo
//////////////////////////////////////////////////////////////////////////
wire [1:0]  bits_enc_fifo_idata,  bits_enc_fifo_odata;
wire        bits_enc_fifo_ivalid, bits_enc_fifo_ovalid;
wire        bits_enc_fifo_iready, bits_enc_fifo_oready;
wire [15:0] bits_enc_fifo_space;
axi_fifo_bram #(.WIDTH(2), .SIZE(10)) bits_enc_fifo(
    .clk(clk), .reset(reset_int), .clear(reset_int),
    .i_tdata(bits_enc_fifo_idata), .i_tvalid(bits_enc_fifo_ivalid), .i_tready(bits_enc_fifo_iready),
    .o_tdata(bits_enc_fifo_odata), .o_tvalid(bits_enc_fifo_ovalid), .o_tready(bits_enc_fifo_oready),
    .space(bits_enc_fifo_space), .occupied()
);
assign bits_enc_fifo_idata  = bits_enc;
assign bits_enc_fifo_ivalid = state1 != S1_WAIT_PKT && state11 < S11_RESET;
assign bits_enc_fifo_oready = (state2 == S2_PUNC_INTERLV && bits_enc_fifo_ovalid == 1 && (enc_pos == 1 || (|punc_info == 1)));

//////////////////////////////////////////////////////////////////////////
// Bit puncturing and bit interleaving
//////////////////////////////////////////////////////////////////////////
// Puncturing and interleaving index look up table
reg  [14:0] ofdm_cnt_FSM2;
reg  [8:0]  dbps_cnt_FSM2;
wire [1:0]  punc_info;
wire [17:0] interlv_addrs;
punc_interlv_lut punc_interlv_lut(
    .rate(PKT_TYPE == LEGACY ? (ofdm_cnt_FSM2 > 0 ? RATE : 5'b01011) : (ofdm_cnt_FSM2 > 2 ? RATE : 5'b01011)),
    .idx_i(dbps_cnt_FSM2),
    .idx_o(interlv_addrs),
    .punc_o(punc_info)
);

// This is a RAM module for holding convolutionally encoded, punctured and interleaved bits.
// Bit puncturing is implicitly carried out, such that punc_interlv_lut provides write address along with puncturing ON/OFF signal
reg        enc_pos;
wire       bits_ram_en;
wire       punc_bit;
wire [8:0] bits_ram_waddr;
reg  [5:0] mod_addr;
wire [5:0] bits_to_mod;
ram_simo #(.DEPTH(52)) bits_ram(
    .clk(clk),
    .waddr(bits_ram_waddr),
    .raddr(mod_addr),
    .wen(bits_ram_en),
    .data_i(punc_bit),
    .data_o(bits_to_mod)
);
assign bits_ram_waddr = enc_pos == 1 ? interlv_addrs[17:9] : (punc_info[0] == 0 ? interlv_addrs[8:0] : interlv_addrs[17:9]);
assign bits_ram_en = (state2 == S2_PUNC_INTERLV);
assign punc_bit = enc_pos == 1 ? bits_enc_fifo_odata[0] : (punc_info[0] == 0 ? bits_enc_fifo_odata[1] : bits_enc_fifo_odata[0]);

//////////////////////////////////////////////////////////////////////////
// Bits modulation
//////////////////////////////////////////////////////////////////////////
// BPSK, QPSK, 16-QAM and 64-QAM modulation
wire [31:0] mod_IQ;
modulation modulation(
    .N_BPSC(PKT_TYPE == LEGACY ? (ofdm_cnt_FSM2 > 0 ? N_BPSC : 3'd1) : (ofdm_cnt_FSM2 > 2 ? N_BPSC : 3'd1)),
    .bits_in(bits_to_mod),
    .IQ(mod_IQ)
);

//////////////////////////////////////////////////////////////////////////
// PILOT, DC (0Hz) and sideband(SB)
//////////////////////////////////////////////////////////////////////////
reg  [31:0] pilot_iq [3:0];
reg  [6:0]  pilot_scram_state;
reg  [3:0]  ht_polarity;
wire        pilot_gain = pilot_scram_state[6] ^ pilot_scram_state[3] ^ 0;
wire [31:0] DC_SB_IQ = {16'h0000, 16'h0000};

//////////////////////////////////////////////////////////////////////////
// Inverse Fast Fourier Transform (IFFT)
//////////////////////////////////////////////////////////////////////////
reg [31:0] ifft_iq;
reg [7:0]  iq_cnt;
always @* begin
    ifft_iq = 0;
    if(state2 == S2_MOD_IFFT_INPUT) begin
        if(iq_cnt == 0 || ((PKT_TYPE == LEGACY || PKT_TYPE == HT && ofdm_cnt_FSM2 <= 2) && iq_cnt >= 27 && iq_cnt < 38) || (PKT_TYPE == HT && ofdm_cnt_FSM2 > 2 && iq_cnt >= 29 && iq_cnt < 36)) begin
            ifft_iq = DC_SB_IQ;
        end else if(iq_cnt == 7) begin
            ifft_iq = pilot_iq[2];
        end else if(iq_cnt == 21) begin
            ifft_iq = pilot_iq[3];
        end else if(iq_cnt == 43) begin
            ifft_iq = pilot_iq[0];
        end else if(iq_cnt == 57) begin
            ifft_iq = pilot_iq[1];
        end else if(iq_cnt < 64) begin
            if(PKT_TYPE == HT && (ofdm_cnt_FSM2 == 1 || ofdm_cnt_FSM2 == 2))
                ifft_iq = {mod_IQ[15:0], mod_IQ[31:16]};
            else
                ifft_iq = mod_IQ;
        end
    end
end

reg         ifft_ce;
wire        ifft_o_sync;
wire [31:0] ifft_o_result;
ifftmain ifft64(
    .i_clk(clk), .i_reset(reset_int),
    .i_ce(ifft_ce),
    .i_sample(ifft_iq),
    .o_result(ifft_o_result),
    .o_sync(ifft_o_sync)
);

//////////////////////////////////////////////////////////////////////////
// DOT11 TX FINITE STATE MACHINE 2
//////////////////////////////////////////////////////////////////////////
wire [8:0]  dbps_size;

always @(posedge clk)
if (reset_int) begin
    dbps_cnt_FSM2 <= 0;
    enc_pos <= 0;
    ofdm_cnt_FSM2 <= 0;
    iq_cnt <= 0;
    ifft_ce <= 0;
    mod_addr <= 0;
    pilot_scram_state <= init_pilot_scram_state;
    ht_polarity <= 4'b1000;
    state2 <= S2_PUNC_INTERLV;

end else begin
    case(state2)
    S2_PUNC_INTERLV: begin
        if(pkt_fifo_space > 63 && CP_fifo_space > 15 && bits_enc_fifo_ovalid == 1) begin
            // The encoding position is shifted only if encoded bits are not punctured
            if(|punc_info == 0)
                enc_pos <= ~enc_pos;

            // If encoding position is on the second place or if encoded bits are punctured
            if(enc_pos == 1 || |punc_info == 1) begin
                if(dbps_cnt_FSM2 == dbps_size-1) begin
                    dbps_cnt_FSM2 <= 0;
                    state2 <= S2_PILOT_DC_SB;

                end else begin
                    dbps_cnt_FSM2 <= dbps_cnt_FSM2 + 1;
                end
            end
        end
    end

    S2_PILOT_DC_SB: begin
        if(PKT_TYPE == HT && ofdm_cnt_FSM2 > 2) begin
            if(ht_polarity[0] ^ pilot_gain == 0)
                pilot_iq[0] <= {16'h4000, 16'h0000};
            else
                pilot_iq[0] <= {16'hC000, 16'h0000};

            if(ht_polarity[1] ^ pilot_gain == 0)
                pilot_iq[1] <= {16'h4000, 16'h0000};
            else
                pilot_iq[1] <= {16'hC000, 16'h0000};

            if(ht_polarity[2] ^ pilot_gain == 0)
                pilot_iq[2] <= {16'h4000, 16'h0000};
            else
                pilot_iq[2] <= {16'hC000, 16'h0000};

            if(ht_polarity[3] ^ pilot_gain == 0)
                pilot_iq[3] <= {16'h4000, 16'h0000};
            else
                pilot_iq[3] <= {16'hC000, 16'h0000};

            ht_polarity <= {ht_polarity[0], ht_polarity[3:1]};
        end else begin
            if(pilot_gain == 0) begin
                pilot_iq[0] <= {16'h4000, 16'h0000};
                pilot_iq[1] <= {16'h4000, 16'h0000};
                pilot_iq[2] <= {16'h4000, 16'h0000};
                pilot_iq[3] <= {16'hC000, 16'h0000};
            end else begin
                pilot_iq[0] <= {16'hC000, 16'h0000};
                pilot_iq[1] <= {16'hC000, 16'h0000};
                pilot_iq[2] <= {16'hC000, 16'h0000};
                pilot_iq[3] <= {16'h4000, 16'h0000};
            end
        end
        pilot_scram_state <= {pilot_scram_state[5:0], (pilot_scram_state[3] ^ pilot_scram_state[6])};

        iq_cnt <= 0;
        ifft_ce <= 1;
        state2 <= S2_MOD_IFFT_INPUT;
    end

    S2_MOD_IFFT_INPUT: begin
        if(iq_cnt < 63) begin
            if(PKT_TYPE == HT && ofdm_cnt_FSM2 > 2) begin
                if(iq_cnt < 6)
                    mod_addr <= iq_cnt[5:0] + 26;
                else if(iq_cnt < 20)
                    mod_addr <= iq_cnt[5:0] + 25;
                else if(iq_cnt < 28)
                    mod_addr <= iq_cnt[5:0] + 24;
                else if(iq_cnt < 42)
                    mod_addr <= iq_cnt[5:0] - 35;
                else if(iq_cnt < 56)
                    mod_addr <= iq_cnt[5:0] - 36;
                else if(iq_cnt < 63)
                    mod_addr <= iq_cnt[5:0] - 37;
            end else begin
                if(iq_cnt < 6)
                    mod_addr <= iq_cnt[5:0] + 24;
                else if(iq_cnt < 20)
                    mod_addr <= iq_cnt[5:0] + 23;
                else if(iq_cnt < 28)
                    mod_addr <= iq_cnt[5:0] + 22;
                else if(iq_cnt < 42)
                    mod_addr <= iq_cnt[5:0] - 37;
                else if(iq_cnt < 56)
                    mod_addr <= iq_cnt[5:0] - 38;
                else if(iq_cnt < 63)
                    mod_addr <= iq_cnt[5:0] - 39;
            end

            iq_cnt <= iq_cnt + 1;

        end else begin
            ifft_ce <= 0;
            ofdm_cnt_FSM2 <= ofdm_cnt_FSM2 + 1;
            state2 <= S2_RESET;
        end
    end

    S2_RESET: begin
        // This is not the last OFDM symbol processed
        if(ofdm_cnt_FSM2 < ofdm_cnt_FSM1) begin
		    state2 <= S2_PUNC_INTERLV;
        end else if(state11 == S11_RESET) begin
            if(pkt_fifo_space > 2 && CP_fifo_space > 2)
                ifft_ce <= 1;
            else
                ifft_ce <= 0;
        end
    end

    default: begin
        state2 <= S2_PUNC_INTERLV;
    end
    endcase
end
assign dbps_size = PKT_TYPE == LEGACY ? (ofdm_cnt_FSM2 > 0 ? N_DBPS : 24) : (ofdm_cnt_FSM2 > 2 ? N_DBPS : 24);

//////////////////////////////////////////////////////////////////////////
// Count number of [pkt/CP] IQ samples to send
//////////////////////////////////////////////////////////////////////////
reg        ifft_status;
reg        ifft_ce_reg;
reg [31:0] ifft_o_result_reg;
reg [5:0]  ifft_o_iq_cnt;
reg [14:0] ifft_o_sync_cnt;
reg [20:0] nof_iq2send;			// 480 + 20169*80 = 1614000 IQ samples
always @(posedge clk)
if (reset_int) begin
    ifft_o_iq_cnt <= 0;
    ifft_o_sync_cnt <= 0;
    ifft_status <= NO_OUTPUT_YET;
    nof_iq2send <= 320;

end else begin
    ifft_o_result_reg <= ifft_o_result;
    ifft_ce_reg <= ifft_ce;

    if(ifft_o_sync == 1) begin
        ifft_o_sync_cnt <= ifft_o_sync_cnt + 1;
        // The moment ifft outputs the first result, we change the status
        if(ifft_status == NO_OUTPUT_YET)
            ifft_status <= OUTPUT_STARTED;
    end

    // IFFT output counter
    if(ifft_status == OUTPUT_STARTED && ifft_ce == 1)
        ifft_o_iq_cnt <= ifft_o_iq_cnt + 1;

    // update number of IQ samples to send
    if(state2 == S2_PILOT_DC_SB) begin
        if(PKT_TYPE == HT) begin
            if(nof_iq2send == 480)
                nof_iq2send <= nof_iq2send + 240;
            else if(nof_iq2send < 480 || S_GI == 0)
                nof_iq2send <= nof_iq2send + 80;
            else
                nof_iq2send <= nof_iq2send + 72;
        end else begin
            nof_iq2send <= nof_iq2send + 80;
        end
    end
end

//////////////////////////////////////////////////////////////////////////
// Cyclic Prefix IFFT output -> Axi stream fifo
//////////////////////////////////////////////////////////////////////////
wire [31:0] CP_fifo_idata,  CP_fifo_odata;
wire        CP_fifo_ivalid, CP_fifo_ovalid;
wire        CP_fifo_iready, CP_fifo_oready;
wire [15:0] CP_fifo_space;
axi_fifo_bram #(.WIDTH(32), .SIZE(6)) CP_fifo(
    .clk(clk), .reset(reset_int), .clear(reset_int),
    .i_tdata(CP_fifo_idata), .i_tvalid(CP_fifo_ivalid), .i_tready(CP_fifo_iready),
    .o_tdata(CP_fifo_odata), .o_tvalid(CP_fifo_ovalid), .o_tready(CP_fifo_oready),
    .space(CP_fifo_space), .occupied()
);
assign CP_fifo_idata  = ifft_o_result_reg;
assign CP_fifo_ivalid = (S_GI == 1 && ifft_o_sync_cnt > 3) ? (ifft_o_iq_cnt[5:3] == 3'b111 ? ifft_ce_reg : 0) : (ifft_o_iq_cnt[5:4] == 2'b11 ? ifft_ce_reg : 0);
assign CP_fifo_oready = (state3 == S3_L_SIG || state3 == S3_HT_SIG || state3 == S3_DATA) && fifo_turn == CP_FIFO ? result_iq_ready : 0;

//////////////////////////////////////////////////////////////////////////
// Packet IFFT output -> Axi stream fifo
//////////////////////////////////////////////////////////////////////////
wire [31:0] pkt_fifo_idata,  pkt_fifo_odata;
wire        pkt_fifo_ivalid, pkt_fifo_ovalid;
wire        pkt_fifo_iready, pkt_fifo_oready;
wire [15:0] pkt_fifo_space;
axi_fifo_bram #(.WIDTH(32), .SIZE(8)) pkt_fifo(
    .clk(clk), .reset(reset_int), .clear(reset_int),
    .i_tdata(pkt_fifo_idata), .i_tvalid(pkt_fifo_ivalid), .i_tready(pkt_fifo_iready),
    .o_tdata(pkt_fifo_odata), .o_tvalid(pkt_fifo_ovalid), .o_tready(pkt_fifo_oready),
    .space(pkt_fifo_space), .occupied()
);
assign pkt_fifo_idata  = ifft_o_result_reg;
assign pkt_fifo_ivalid = ifft_status == OUTPUT_STARTED ? ifft_ce_reg : 0;
assign pkt_fifo_oready = (state3 == S3_L_SIG || state3 == S3_HT_SIG || state3 == S3_DATA) && fifo_turn == PKT_FIFO ? result_iq_ready : 0;

//////////////////////////////////////////////////////////////////////////
// Count number of [pkt/CP] IQ samples sent
//////////////////////////////////////////////////////////////////////////
reg        fifo_turn;
reg [20:0] pkt_iq_sent;
reg [18:0] CP_iq_sent;
always @(posedge clk)
if (reset_int) begin
    fifo_turn   <= PKT_FIFO;
    pkt_iq_sent <= 0;
    CP_iq_sent  <= 0;

end else begin
    if(result_iq_ready == 1 && result_iq_valid == 1) begin
        if(fifo_turn == PKT_FIFO) begin
            if(pkt_iq_sent[5:0] == 6'b111111 && |pkt_iq_sent[15:8] == 1)
                fifo_turn <= CP_FIFO;
            pkt_iq_sent   <= pkt_iq_sent + 1;
        end else if(fifo_turn == CP_FIFO) begin
            if((pkt_iq_sent < 640 && CP_iq_sent[3:0] == 4'b1111) || (S_GI == 0 && CP_iq_sent[3:0] == 4'b1111) || (S_GI == 1 && pkt_iq_sent >= 640 && CP_iq_sent[2:0] == 3'b111))
                fifo_turn <= PKT_FIFO;
            CP_iq_sent    <= CP_iq_sent + 1;
        end
    end
end

//////////////////////////////////////////////////////////////////////////
// DOT11 TX FINITE STATE MACHINE 3
//////////////////////////////////////////////////////////////////////////
always @(posedge clk)
if (reset_int) begin
    preamble_addr <= 0;
    phy_tx_done <= 0;
    FSM3_reset <= 0;

    state3 <= S3_WAIT_PKT;

end else if(result_iq_ready == 1) begin
    case(state3)
    S3_WAIT_PKT: begin
        if(phy_tx_start) begin
            preamble_addr <= 0;
            state3 <= S3_L_STF;
        end
    end

    S3_L_STF: begin
        // Legacy short preamble contains 10*16 = 160 samples
        if(preamble_addr < 159) begin
            preamble_addr <= preamble_addr + 1;
        end else begin
            preamble_addr <= 0;
            state3 <= S3_L_LTF;
        end

        // Send "OPERATION STARTED" message to upper layer
        if(preamble_addr == 0)
            phy_tx_started <= 1;
        else
            phy_tx_started <= 0;
    end

    S3_L_LTF: begin
        // Legacy long preamble contains 160 samples
        if(preamble_addr < 159) begin
            preamble_addr <= preamble_addr + 1;

        end else begin
            state3 <= S3_L_SIG;
        end
    end

    S3_L_SIG: begin
        // Legacy SIGNAL contains 80 samples
        if(pkt_iq_sent == 383 && CP_iq_sent == 16) begin
            if(PKT_TYPE == LEGACY)
                state3 <= S3_DATA;
            else
                state3 <= S3_HT_SIG;
        end
    end

    S3_HT_SIG: begin
        // HT SIGNAL contains 160 samples
        if(pkt_iq_sent == 511 && CP_iq_sent == 48) begin
            preamble_addr <= 0;
            state3 <= S3_HT_STF;
        end
    end

    S3_HT_STF: begin
        // HT short preamble contains 5*16 = 80 samples
        if(preamble_addr < 79) begin
            preamble_addr <= preamble_addr + 1;
        end else begin
            preamble_addr <= 0;
            state3 <= S3_HT_LTF;
        end
    end

    S3_HT_LTF: begin
        // HT long preamble contains 80 samples
        if(preamble_addr < 79) begin
            preamble_addr <= preamble_addr + 1;

        end else begin
            state3 <= S3_DATA;
        end
    end

    S3_DATA: begin
        if((pkt_iq_sent + {2'b00, CP_iq_sent}) == nof_iq2send-2) begin
            phy_tx_done <= 1;
            FSM3_reset <= 1;
        end
    end
    endcase
end

assign result_i        = state3 == S3_L_STF ? l_stf[31:16] : (state3 == S3_L_LTF ? l_ltf[31:16] : (state3 == S3_HT_STF ? ht_stf[31:16] : (state3 == S3_HT_LTF ? ht_ltf[31:16] : (fifo_turn == PKT_FIFO ? pkt_fifo_odata[31:16] : CP_fifo_odata[31:16]))));
assign result_q        = state3 == S3_L_STF ? l_stf[15:0]  : (state3 == S3_L_LTF ? l_ltf[15:0]  : (state3 == S3_HT_STF ? ht_stf[15:0]  : (state3 == S3_HT_LTF ? ht_ltf[15:0]  : (fifo_turn == PKT_FIFO ? pkt_fifo_odata[15:0]  : CP_fifo_odata[15:0]))));
assign result_iq_valid = state3 == S3_L_STF || state3 == S3_L_LTF || state3 == S3_HT_STF || state3 == S3_HT_LTF ? 1 : (fifo_turn == PKT_FIFO ? pkt_fifo_ovalid : CP_fifo_ovalid);

endmodule

////////////////////////////////////////////////////////////////////////////////
//
// Filename:	ifftmain.v
//
// Project:	A General Purpose Pipelined FFT Implementation
//
// Purpose:	This is the main module in the General Purpose FPGA FFT
//		implementation.  As such, all other modules are subordinate
//	to this one.  This module accomplish a fixed size Complex FFT on
//	64 data points.
//	The FFT is fully pipelined, and accepts as inputs one complex two's
//	complement sample per clock.
//
// Parameters:
//	i_clk	The clock.  All operations are synchronous with this clock.
//	i_reset	Synchronous reset, active high.  Setting this line will
//			force the reset of all of the internals to this routine.
//			Further, following a reset, the o_sync line will go
//			high the same time the first output sample is valid.
//	i_ce	A clock enable line.  If this line is set, this module
//			will accept one complex input value, and produce
//			one (possibly empty) complex output value.
//	i_sample	The complex input sample.  This value is split
//			into two two's complement numbers, 16 bits each, with
//			the real portion in the high order bits, and the
//			imaginary portion taking the bottom 16 bits.
//	o_result	The output result, of the same format as i_sample,
//			only having 16 bits for each of the real and imaginary
//			components, leading to 32 bits total.
//	o_sync	A one bit output indicating the first sample of the FFT frame.
//			It also indicates the first valid sample out of the FFT
//			on the first frame.
//
// Arguments:	This file was computer generated using the following command
//		line:
//
//		% ./fftgen -v -i -d ../../ifft64 -f 64 -1 -k 1 -p 12 -n 16 -m 16
//
//	This core will use hardware accelerated multiplies (DSPs)
//	for 4 of the 6 stages
//
// Creator:	Dan Gisselquist, Ph.D.
//		Gisselquist Technology, LLC
//
////////////////////////////////////////////////////////////////////////////////
//
// Copyright (C) 2015-2019, Gisselquist Technology, LLC
//
// This file is part of the general purpose pipelined FFT project.
//
// The pipelined FFT project is free software (firmware): you can redistribute
// it and/or modify it under the terms of the GNU Lesser General Public License
// as published by the Free Software Foundation, either version 3 of the
// License, or (at your option) any later version.
//
// The pipelined FFT project is distributed in the hope that it will be useful,
// but WITHOUT ANY WARRANTY; without even the implied warranty of
// MERCHANTIBILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the GNU Lesser
// General Public License for more details.
//
// You should have received a copy of the GNU Lesser General Public License
// along with this program.  (It's in the $(ROOT)/doc directory.  Run make
// with no target there if the PDF file isn't present.)  If not, see
// <http://www.gnu.org/licenses/> for a copy.
//
// License:	LGPL, v3, as defined and found on www.gnu.org,
//		http://www.gnu.org/licenses/lgpl.html
//
//
////////////////////////////////////////////////////////////////////////////////
//
//
//`default_nettype	none
//
//
//
module ifftmain(i_clk, i_reset, i_ce,
		i_sample, o_result, o_sync);
	// The bit-width of the input, IWIDTH, output, OWIDTH, and the log
	// of the FFT size.  These are localparams, rather than parameters,
	// because once the core has been generated, they can no longer be
	// changed.  (These values can be adjusted by running the core
	// generator again.)  The reason is simply that these values have
	// been hardwired into the core at several places.
	localparam	IWIDTH=16, OWIDTH=16, LGWIDTH=6;
	//
	input	wire				i_clk, i_reset, i_ce;
	//
	input	wire	[(2*IWIDTH-1):0]	i_sample;
	output	reg	[(2*OWIDTH-1):0]	o_result;
	output	reg				o_sync;


	// Outputs of the FFT, ready for bit reversal.
	wire				br_sync;
	wire	[(2*OWIDTH-1):0]	br_result;


	// A hardware optimized FFT stage
	wire		w_s64;
	wire	[31:0]	w_d64;
	fftstage	#(IWIDTH,IWIDTH+4,16,5,0,
			1, 1, "icmem_64.mem")
		stage_64(i_clk, i_reset, i_ce,
			(!i_reset), i_sample, w_d64, w_s64);


	// A hardware optimized FFT stage
	wire		w_s32;
	wire	[31:0]	w_d32;
	fftstage	#(16,20,16,4,0,
			1, 1, "icmem_32.mem")
		stage_32(i_clk, i_reset, i_ce,
			w_s64, w_d64, w_d32, w_s32);

	// A hardware optimized FFT stage
	wire		w_s16;
	wire	[31:0]	w_d16;
	fftstage	#(16,20,16,3,0,
			1, 1, "icmem_16.mem")
		stage_16(i_clk, i_reset, i_ce,
			w_s32, w_d32, w_d16, w_s16);

	// A hardware optimized FFT stage
	wire		w_s8;
	wire	[31:0]	w_d8;
	fftstage	#(16,20,16,2,0,
			1, 1, "icmem_8.mem")
		stage_8(i_clk, i_reset, i_ce,
			w_s16, w_d16, w_d8, w_s8);

	wire		w_s4;
	wire	[31:0]	w_d4;
	qtrstage	#(16,16,6,1,0)	stage_4(i_clk, i_reset, i_ce,
						w_s8, w_d8, w_d4, w_s4);
	wire		w_s2;
	wire	[31:0]	w_d2;
	laststage	#(16,16,1)	stage_2(i_clk, i_reset, i_ce,
					w_s4, w_d4, w_d2, w_s2);


	wire	br_start;
	reg	r_br_started;
	initial	r_br_started = 1'b0;
	always @(posedge i_clk)
		if (i_reset)
			r_br_started <= 1'b0;
		else if (i_ce)
			r_br_started <= r_br_started || w_s2;
	assign	br_start = r_br_started || w_s2;

	// Now for the bit-reversal stage.
	bitreverse	#(6,16)
		revstage(i_clk, i_reset,
			(i_ce & br_start), w_d2,
			br_result, br_sync);


	// Last clock: Register our outputs, we're done.
	initial	o_sync  = 1'b0;
	always @(posedge i_clk)
	if (i_reset)
		o_sync  <= 1'b0;
	else if (i_ce)
		o_sync  <= br_sync;

	always @(posedge i_clk)
	if (i_ce)
		o_result  <= br_result;


endmodule

